var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>제 1종 침식체와의 모의전투 종료.</color>","JPN":"<color=#ffd34c>第1種侵食体との模擬戦闘終了。</color>","ENG":"<color=#ffd34c>Ending simulated combat against Category 1 Corrupted Object.</color>","TWN":"<color=#ffd34c>完成與1類侵蝕體的模擬戰鬥。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>가상 전투 환경을 해제합니다.</color>","JPN":"<color=#ffd34c>仮想戦闘環境を解除します。</color>","ENG":"<color=#ffd34c>Exiting virtual combat environment mode.</color>","TWN":"<color=#ffd34c>解除虛擬戰鬥環境。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>전투 결과 연산 중...... 완료.</color>","JPN":"<color=#ffd34c>戦闘結果演算中……完了。</color>","ENG":"<color=#ffd34c>Calculating combat results... Completed.</color>","TWN":"<color=#ffd34c>正在演算戰鬥結果……已完成。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIMULATOR_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>전투 랭크 — 완벽함.</color>","JPN":"<color=#ffd34c>戦闘ランク — 完璧。</color>","ENG":"<color=#ffd34c>Combat Rank: Perfect.</color>","TWN":"<color=#ffd34c>戰鬥等級——完美。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어? 어어?","JPN":"えっ？　ええっ？","ENG":"Huh? What?","TWN":"唉？唉？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"완벽함 랭크라고? 정말?","JPN":"ランクが完璧？　本当に？","ENG":"Perfect? For real?","TWN":"完美等級？真的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"말해준 대로 그렇게 어렵진 않은데?","JPN":"言われたとおりそんなに難しくないね。","ENG":"Hey, that wasn't so bad like you said.","TWN":"果然跟你說的一樣，很簡單？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"말도 안 돼! 아무리 튜토리얼 스테이지라지만 침식체와 싸우는 일이라고!","JPN":"あり得ないよ！　いくらチュートリアルステージとはいえ、侵食体と戦うんだよ？","ENG":"No way! This may be just a tutorial stage, but that was a simulated C.O.!","TWN":"不可能！就算是新手教程關卡，也還是需要跟侵蝕體戰鬥啊！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"클리어는 고사하고 기절하는 친구들도 많은데 단번에 완벽함 랭크라고?","JPN":"クリアどころか、気絶する子が大半なのにこんな簡単に完璧ランクが出る……？","ENG":"Most students barely manage to stay conscious till the end; you let alone clear the stage and even got a perfect score?","TWN":"別說是通關，我見到很多學生甚至會暈倒，怎麼可能是完美等級？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......너 타기 전에 튜토리얼 스테이지는 쉬우니까 걱정하지 말라고 하지 않았어?","JPN":"……でも、始まる前にチュートリアルステージは簡単だから心配は要らないって言ったでしょ？","ENG":"Um... Didn't you tell me not to worry since the tutorial's pretty easy?","TWN":"…在我坐上去前，你不是說新手教程關卡很簡單，讓我不用擔心嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그건...... 미나는 실전도 많이 경험한 용병이라고 들었으니까.","JPN":"そ、それは……ミナちゃんは実戦経験豊富な傭兵って聞いたから。","ENG":"W-well... I mean, I heard you've had plenty of combat experience as a mercenary...","TWN":"那…那個……是因為我早就聽說米娜是有豐富實戰經驗的傭兵了嘛。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"기준을 쪼오금 높여서 이야기 한 거지.","JPN":"ちょっとだけハードルを上げて話したの。","ENG":"So I may have exaggerated things a bit to meet your standards.","TWN":"所以說的時候，稍微提高了些標準。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐...... 경험이 적지는 않지.","JPN":"まあ……経験は少ないほうではないけどね。","ENG":"Well... I guess I wouldn't say I'm inexperienced.","TWN":"嗯……經驗確實不算少。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래도 정말 대단해. 예전에도 태스크포스 출신 편입생들이 있었거든.","JPN":"それでも本当にすごいよ。以前もタスクフォース出身の編入生はいたの。","ENG":"Still, that was so amazing. We had transfer students from TASKFORCEs before.","TWN":"不過你真厲害。以前也有過特遣勢力出身的學生。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"대부분은 시뮬레이터를 처음 써 보면 당황해서 제 실력이 안 나왔는데......","JPN":"でもほとんどの子はシミュレーターが始めてだから、慌てて本来の実力が発揮できなかったのに……","ENG":"But most of them freaked out in the simulator and couldn't perform their best...","TWN":"不過大部分都因為第一次接觸模擬器，沒辦法完全發揮自己的實力……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나 넌 어떻게 그렇게 잘하는 거야?","JPN":"ミナちゃんはどうしてそんなに上手いの？","ENG":"How come you're so good at this?","TWN":"米娜，你怎麼那麼厲害？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아마...... 우리 회사에도 비슷한 게 있어서 그런 거 아닐까?","JPN":"たぶん……うちの会社に似たようなものがあるからかな？","ENG":"Well... Probably because we've got something similar at my company?","TWN":"可能……是因為我們公司也有類似的模擬器吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"훈련할 때 자주 썼거든.","JPN":"訓練の時よく使っているから。","ENG":"We used it a lot for training.","TWN":"訓練的時候經常用到。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 보통은 거대로봇에 탄 사장님한테 엉망진창 험한 꼴을 당했지만.","JPN":"まぁ、毎回巨大ロボットに乗った社長にメチャクチャにされてとんでもない目に遭わされたけどね。","ENG":"Most of the time, we'd get our butts kicked by our Boss piloting a giant robot though.","TWN":"雖然，通常都是被巨大的機器人老闆暴打。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그거야말로 말도 안 되는 이야기야!","JPN":"そ、それこそあり得ない話だよ！","ENG":"Th-that's impossible!","TWN":"這、這怎麼可能！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이건 아카데미에도 설치된 지 얼마 안 된 관리국의 최신 장비라고!","JPN":"これはアカデミーに設置されたばかりの、管理局の最新装備なの！","ENG":"This is the Administration's cutting edge equipment! It's brand new!","TWN":"這台機器在學院安裝沒多久，在管理局也是最新裝備！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"여러 가지 환경에 제 3종 침식체까지 구현할 수 있는 엄청난 물건인데......","JPN":"様々な環境に第3種侵食体まで具現できる特別なものなのに……","ENG":"It can simulate all sorts of environments, and even Category 3 C.O.s...","TWN":"不僅能模擬各種環境，還是能具現3類侵蝕體的超級裝備……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런 게 일반 태스크포스 컴퍼니에 있을 리 없잖아!","JPN":"そんなものが一般タスクフォースカンパニーにあるはずがない！","ENG":"There's no way something like this could exist at a TASKFORCE company!","TWN":"普通的特遣勢力公司怎麼可能會有！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이, 있는 걸 있다고 말하지 그럼 어떻게 해.","JPN":"で、でも実際にある物をないって言うのもおかしくない？","ENG":"W-well, I saw one at mine... What else can I say?","TWN":"我難道會騙你嗎，真的就是有嘛。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그것도 내가 입사하기 한참 전부터 사용했다고 들었는데......","JPN":"それも私が入社するずっと前から使っていたと聞いたし……","ENG":"I heard they've been using it for ages, before I even joined the company...","TWN":"而且早在我入職前就有了，已經用很久了……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"한참 전부터? 대체 뭐 하는 회사길래......?","JPN":"ずっと前？　いったいどんな会社なの……？","ENG":"Ages before? What kind of company is this?","TWN":"很久前？你們到底是什麼公司……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_Q","text":{"KOREA":"시...... 실례합니다.","JPN":"し……失礼します。","ENG":"E-excuse me.","TWN":"打……打擾一下。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_Q","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};